#include "lsmps.hpp"
#include <filesystem>
#include <iomanip>
#include <iostream>
int main(int argc,char**argv){try{std::string cp=argc>1?argv[1]:"config/wall_film.cfg",od=argc>2?argv[2]:"results";auto c=lsmps::load_config(cp);auto p=lsmps::generate_case(c);auto m=lsmps::run_benchmark(c,p);std::filesystem::create_directories(od);auto b=od+"/"+c.case_name;lsmps::write_json(b+".json",c,m);lsmps::write_csv(b+".csv",c,m);std::cout<<"LS-MPS industrial benchmark v0.4\ncase="<<c.case_name<<" particles="<<m.particles<<"\ntypes interior="<<m.interior<<" surface="<<m.free_surface<<" splash="<<m.splash<<" near_wall="<<m.near_wall<<" wall="<<m.wall<<"\n"<<std::fixed<<std::setprecision(2)<<"neighbors mean="<<m.neighbor_mean<<" p50="<<m.neighbor_p50<<" p90="<<m.neighbor_p90<<" p99="<<m.neighbor_p99<<"\nWLS sampled="<<m.wls.sampled<<" regularized="<<m.wls.regularized<<" failed="<<m.wls.failed<<" virtual="<<m.wls.virtual_points<<" grad_rms="<<std::scientific<<m.wls.rms_gradient_error<<" lap_rms="<<m.wls.rms_laplacian_error<<"\nPPE unknowns="<<m.ppe.unknowns<<" nnz="<<m.ppe.nnz<<" iterations="<<m.ppe.iterations<<" converged="<<m.ppe.converged<<" residual="<<m.ppe.final_residual<<" rel_l2="<<m.ppe.relative_l2_error<<"\nPPE timing(ms) assembly="<<std::fixed<<m.ppe.assembly_ms<<" solve="<<m.ppe.solve_ms<<"\noutput="<<b<<".{json,csv}\n";return (!m.ppe.converged||m.wls.failed>m.wls.sampled/5)?2:0;}catch(const std::exception&e){std::cerr<<"error: "<<e.what()<<'\n';return 1;}}
